module combinational_circuit(
    input [3:0] A,
    input [1:0] B,
    input C,
    input D,
    input E,
    output X
);

    wire inverted_logic_result = ((A <= 5) && (B == 2)) ? 1 :
               ((C == 1) && (D == 0) && (E == 1)) ? 1 : 0;
    assign X = inverted_logic_result;

endmodule
